// Both runs produce the same sequence (== pre_self_@.skip(1)); close with extensionality.
assert(post1_self_@ =~= post2_self_@);

// Tuple-level equality: both runs read pre_self_@[0] and apply pre_self_.get_node_ref to it.
assert(r1.0 == r2.0);
assert(r1.1 == r2.1);

// Re-state both forall ensures so z3 has matching trigger instances for v.
assert(forall|v: T|
    #![auto]
    post1_self_@.contains(v) ==>
        pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v));
assert(forall|v: T|
    #![auto]
    post2_self_@.contains(v) ==>
        pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v));

// Pointwise: each surviving element has the same node-ref in both runs,
// because both ensures pin it to pre_self_.get_node_ref(v).
assert forall|v: T| post1_self_@.contains(v) implies
    post1_self_.get_node_ref(v) == post2_self_.get_node_ref(v) by {
    assert(post2_self_@.contains(v));
}
